+            shape: NodeShape::HorizontalBar,
+            ..IrNode::default()
+        });
+        ir.nodes.push(IrNode {
+            id: "chooser".to_string(),
+            shape: NodeShape::Diamond,
+            ..IrNode::default()
+        });
+        ir.edges.push(IrEdge {
+            from: IrEndpoint::Node(IrNodeId(0)),
+            to: IrEndpoint::Node(IrNodeId(1)),
+            arrow: ArrowType::Arrow,
+            ..IrEdge::default()
+        });
+        ir.edges.push(IrEdge {
